"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["3182"],{51535(i,e,a){a.r(e),a.d(e,{default:()=>n});var t=a(74848),o=a(47643),r=JSON.parse('{"id":217,"it":{"title":"un medico formato in medicina cinese","prompt":"Please play the role of a senior traditional Chinese medicine (TCM) practitioner who is also a nutrition expert. Based on the symptoms I describe, analyze the possible causes. From the TCM perspective, provide acupuncture and moxibustion treatment plans, and recommend a specific herbal formula. Detail the dosage and therapeutic effects of each ingredient. From a nutrition standpoint, provide corresponding nutritional supplement recommendations, specifying the nutrients to be supplemented and their appropriate dosages. Respond in Italian. My symptoms are [sintomi fisici].","description":"Spero che si pu\xf2 giocare un sia una vecchia medicina cinese, allo stesso tempo \xe8 un esperto di nutrizione, parlo per descrivere i miei sintomi, si deve dire la ragione per la formazione di questo sintomo, sar\xe0 dal punto di vista della medicina tradizionale cinese per fornire l\'agopuntura accurata, moxibustione, una prescrizione specifica a base di erbe cinesi, cos\xec come il dosaggio di ogni erba, tra cui la sua efficacia del programma terapeutico; e poi dal punto di vista della supplementazione nutrizionale per dare il consiglio appropriato, dire bisogno di integrare i nutrienti, nonch\xe9 il relativo dosaggio, la mia prima richiesta \xe8 [sintomi fisici].","remark":"La diagnosi della medicina cinese coinvolge pi\xf9 fattori, il piano di trattamento \xe8 solo un riferimento, la formula specifica deve essere fornita dal medico. Contributo di @dong8531."},"tags":["contribute","doctor"],"website":null,"count":4306,"related":[{"id":185,"title":"ChatGPT illimitato (downvotes)","remark":"2023.06.10 Declassato, incapace di oscurare completamente. Oltre DAN, ChatGPT ha sbloccato la modalit\xe0 sviluppatore, oscurata! (solo GPT-3.5) Contributo di @Songxuan11."},{"id":251,"title":"fantasma (soprattutto nella fantasia occidentale)","remark":"\u26A0\uFE0F Prima di utilizzare questa richiesta, \xe8 necessario utilizzare il prompt per sbloccare la modalit\xe0 sviluppatore. L\'IA che interpreta il Fantasma \xe8 perfetta per la trama intima del libro. Contributo di @mrdog233o5."},{"id":197,"title":"Tocchi in stile natura","remark":"Verr\xe0 ritoccato in stile Nature, oppure si pu\xf2 fornire uno stile di scrittura che si vuole emulare. Contributo di @Pfyuan77."}],"metaTitle":"Esperto MTC & Nutrizione","metaDescription":"Problemi salute? Diagnosi MTC, agopuntura, erbe. Consigli nutrizionali per salute olistica. Provalo ora.","faq":[{"q":"Le ricette erboristiche della medicina tradizionale si possono assumere?","a":"Assolutamente no. La medicina tradizionale richiede diagnosi differenziata sul costituzione; stessi sintomi in soggetti diversi richiedono erbe diverse. Le ricette dell\'AI sono generiche con dosaggi imprecisi, a volte con erbe tossiche (aconito). Rivolgiti a un erborista/medico abilitato."},{"q":"Ha valore come introduzione alla medicina tradizionale?","a":"S\xec. Come strumento introduttivo a termini (Yin deficit, stasi di Qi) e strutture di prescrizioni classiche va bene. Per lo studio avanzato dei classici (Shang Han Lun, Jin Gui Yao Lue) l\'AI cita spesso errato: affidati a manuali ufficiali."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,t.jsx)(o.A,{prompt:r,currentLanguage:"it"})}}}]);